class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val=val; self.left=left; self.right=right

def postorder(root):
    if not root:
        return []
    # Modified pre-order: Root -> Right -> Left (note: right before left)
    stack  = [root]
    result = []
    while stack:
        node = stack.pop()
        result.append(node.val)
        if node.left:  stack.append(___________)
        if node.right: stack.append(___________)
    return result[::-1]   # reverse gives Left -> Right -> Root
